        uint32_t rowIdx = blockIdx;

        while (rowIdx < batchSize_) {
            uint32_t offset = rowIdx * dimSize_;
            CopyInRow(offset, dimSize_);
            ComputeRowSoftmax(dimSize_);
            CopyOutRow(offset, dimSize_);
            rowIdx += rowStride;
        }
