            uint32_t rowOffset = rowIdx * dimSize_;

            for (uint32_t tileIdx = 0; tileIdx < tileRowNum_; ++tileIdx) {
                uint32_t tileOffset = rowOffset + tileIdx * ELEMENTS_PER_TILE;
